-- Add BM25 full-text search indexes for UI entity search.
-- Replaces vector-based KNN search (which requires embedding API calls per query)
-- with fast, deterministic full-text search using SurrealDB analyzers.

BEGIN TRANSACTION;

DEFINE ANALYZER OVERWRITE entity_search
  TOKENIZERS blank, class, camel, punct
  FILTERS snowball(english), lowercase;

-- Entity text fields indexed for full-text search
DEFINE INDEX OVERWRITE idx_task_fulltext ON task FIELDS title FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_decision_fulltext ON decision FIELDS summary FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_question_fulltext ON question FIELDS text FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_observation_fulltext ON observation FIELDS text FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_feature_fulltext ON feature FIELDS name FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_project_fulltext ON project FIELDS name FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_person_fulltext ON person FIELDS name FULLTEXT ANALYZER entity_search BM25;
DEFINE INDEX OVERWRITE idx_message_fulltext ON message FIELDS text FULLTEXT ANALYZER entity_search BM25;

-- Replace KNN vector search functions with BM25 full-text search.
-- First param changes from $vec (embedding) to $query (string).
DEFINE FUNCTION OVERWRITE fn::entity_search_workspace($query: string, $limit: int, $workspace: record<workspace>) {
  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);

  LET $task_rows = SELECT
    id, "task" AS kind, title AS text,
    search::score(1) AS score
  FROM task
  WHERE title @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $decision_rows = SELECT
    id, "decision" AS kind, summary AS text,
    search::score(1) AS score
  FROM decision
  WHERE summary @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $question_rows = SELECT
    id, "question" AS kind, text AS text,
    search::score(1) AS score
  FROM question
  WHERE text @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $observation_rows = SELECT
    id, "observation" AS kind, text AS text,
    search::score(1) AS score
  FROM observation
  WHERE text @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $feature_rows = SELECT
    id, "feature" AS kind, name AS text,
    search::score(1) AS score
  FROM feature
  WHERE name @1@ $query
  ORDER BY score DESC LIMIT $safe_limit;

  LET $project_rows = SELECT
    id, "project" AS kind, name AS text,
    search::score(1) AS score
  FROM project
  WHERE name @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $person_rows = SELECT
    id, "person" AS kind, name AS text,
    search::score(1) AS score
  FROM person
  WHERE name @1@ $query
  ORDER BY score DESC LIMIT $safe_limit;

  LET $message_rows = SELECT
    id, "message" AS kind, text AS text,
    search::score(1) AS score
  FROM message
  WHERE text @1@ $query AND conversation.workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $all = array::flatten([$task_rows, $decision_rows, $question_rows, $observation_rows, $feature_rows, $project_rows, $person_rows, $message_rows]);
  RETURN SELECT * FROM $all ORDER BY score DESC LIMIT $safe_limit;
};

DEFINE FUNCTION OVERWRITE fn::entity_search_project($query: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;

  LET $task_rows = SELECT
    id, "task" AS kind, title AS text,
    search::score(1) AS score
  FROM task
  WHERE title @1@ $query AND workspace = $workspace AND id IN $project_entity_ids
  ORDER BY score DESC LIMIT $safe_limit;

  LET $decision_rows = SELECT
    id, "decision" AS kind, summary AS text,
    search::score(1) AS score
  FROM decision
  WHERE summary @1@ $query AND workspace = $workspace AND id IN $project_entity_ids
  ORDER BY score DESC LIMIT $safe_limit;

  LET $question_rows = SELECT
    id, "question" AS kind, text AS text,
    search::score(1) AS score
  FROM question
  WHERE text @1@ $query AND workspace = $workspace AND id IN $project_entity_ids
  ORDER BY score DESC LIMIT $safe_limit;

  LET $observation_rows = SELECT
    id, "observation" AS kind, text AS text,
    search::score(1) AS score
  FROM observation
  WHERE text @1@ $query AND workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $feature_rows = SELECT
    id, "feature" AS kind, name AS text,
    search::score(1) AS score
  FROM feature
  WHERE name @1@ $query AND id IN $project_entity_ids
  ORDER BY score DESC LIMIT $safe_limit;

  LET $message_rows = SELECT
    id, "message" AS kind, text AS text,
    search::score(1) AS score
  FROM message
  WHERE text @1@ $query AND conversation.workspace = $workspace
  ORDER BY score DESC LIMIT $safe_limit;

  LET $all = array::flatten([$task_rows, $decision_rows, $question_rows, $observation_rows, $feature_rows, $message_rows]);
  RETURN SELECT * FROM $all ORDER BY score DESC LIMIT $safe_limit;
};

COMMIT TRANSACTION;

